import{_ as t,o as i,c as o,ag as r}from"./chunks/framework.OsDJF_Ea.js";const g=JSON.parse('{"title":"Golden Path (Self-Service Provisioning)","description":"Platform-defined service templates that let developers provision new services without knowing the underlying infrastructure.","frontmatter":{"title":"Golden Path (Self-Service Provisioning)","description":"Platform-defined service templates that let developers provision new services without knowing the underlying infrastructure."},"headers":[],"relativePath":"portals/devx/golden-path.md","filePath":"portals/devx/golden-path.md"}'),a={name:"portals/devx/golden-path.md"};function n(s,e,l,d,p,h){return i(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="golden-path-self-service-provisioning" tabindex="-1">Golden Path (Self-Service Provisioning) <a class="header-anchor" href="#golden-path-self-service-provisioning" aria-label="Permalink to &quot;Golden Path (Self-Service Provisioning)&quot;">​</a></h1><p><strong>Route:</strong> <code>/golden-path</code> · <strong>Edition:</strong> Community+</p><p>Golden Path lets platform teams define reusable service templates, and lets developers provision new services from those templates in a few clicks — without needing to know the underlying infrastructure details.</p><h2 id="templates" tabindex="-1">Templates <a class="header-anchor" href="#templates" aria-label="Permalink to &quot;Templates&quot;">​</a></h2><p>Templates define what gets created when a developer requests a new service. Each template includes:</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td>Name</td><td>Template display name (e.g. &quot;Go Microservice&quot;)</td></tr><tr><td>Description</td><td>What kind of service it creates</td></tr><tr><td>Variables</td><td>Input fields the developer fills in (name, team, region, etc.)</td></tr><tr><td>n8n workflow ID</td><td>The automation workflow that handles the actual provisioning</td></tr></tbody></table><p>Templates are created and managed by platform admins. Developers only see the <strong>provision</strong> form.</p><h2 id="provisioning-a-service" tabindex="-1">Provisioning a service <a class="header-anchor" href="#provisioning-a-service" aria-label="Permalink to &quot;Provisioning a service&quot;">​</a></h2><ol><li>Browse the template list and click a template</li><li>Fill in the requested variables (service name, team, etc.)</li><li>Click <strong>Provision</strong> — this triggers the linked n8n workflow</li><li>You&#39;re taken to the <strong>Provisioning Status</strong> page which polls for completion</li></ol><h2 id="provisioning-history" tabindex="-1">Provisioning history <a class="header-anchor" href="#provisioning-history" aria-label="Permalink to &quot;Provisioning history&quot;">​</a></h2><p>The <strong>History</strong> tab shows all past provisioning requests with status, template used, and timestamp — useful for audits and debugging failed provisioning runs.</p>',11)])])}const v=t(a,[["render",n]]);export{g as __pageData,v as default};
